import request from '@/utils/request'

// 档案数据管理
const profile = {
  // 获取完整档案数据
  getData() {
    return request.get('/api/v1/users/profile/data/')
  },

  // 更新模块数据
  updateModule(type, data) {
    return request({
      url: `/api/v1/users/profile/${type}/`,
      method: 'put',
      data
    })
  },

  // 添加模块项目
  addModuleItem(type, data) {
    return request({
      url: `/api/v1/users/profile/${type}/`,
      method: 'post',
      data
    })
  },

  // 删除模块项目
  deleteModuleItem(type, id) {
    return request({
      url: `/api/v1/users/profile/${type}/${id}/`,
      method: 'delete'
    })
  }
}

// 导出 profile 对象
export default profile
